package _02_mouse_interactions;

import org.openqa.selenium.By;
import org.openqa.selenium.Keys;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.chrome.ChromeDriver;
import org.openqa.selenium.interactions.Actions;

import java.time.Duration;

public class _01_MouseActions {
    public static void main(String[] args) {
        WebDriver driver = new ChromeDriver();
        driver.manage().timeouts().implicitlyWait(Duration.ofSeconds(5));
        driver.manage().window().maximize();
        driver.get("https://www.amazon.in/");

        WebElement signIn = driver.findElement(By.xpath("//div[@id='nav-link-accountList']//a[@data-nav-role='signin']"));
        WebElement search = driver.findElement(By.xpath("//input[@id='twotabsearchtextbox']"));

        Actions actions = new Actions(driver);

        actions.moveToElement(signIn).contextClick().build().perform();

        actions.moveToElement(search).click().keyDown(Keys.SHIFT).sendKeys("akbar").doubleClick().build().perform();

        driver.quit();
    }
}

package _02_mouse_interactions;

import org.openqa.selenium.By;
import org.openqa.selenium.Keys;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.chrome.ChromeDriver;
import org.openqa.selenium.interactions.Actions;

import java.time.Duration;

/**
 * Demonstrates advanced mouse interactions using Selenium WebDriver's Actions class.
 * 
 * This class showcases how to perform complex mouse operations such as moving to elements,
 * right-clicking (context click), clicking, typing with keyboard modifiers, and double-clicking.
 * It uses Amazon India's homepage as a test environment to demonstrate these interactions.
 * 
 * <p><strong>Prerequisites:</strong></p>
 * <ul>
 *   <li>ChromeDriver must be available in the system PATH or configured</li>
 *   <li>Chrome browser must be installed</li>
 *   <li>Internet connection is required to access Amazon.in</li>
 *   <li>Selenium WebDriver dependencies must be properly configured</li>
 * </ul>
 * 
 * <p><strong>Features Demonstrated:</strong></p>
 * <ul>
 *   <li>Mouse movement to elements</li>
 *   <li>Context click (right-click)</li>
 *   <li>Click and keyboard input with modifiers</li>
 *   <li>Double-click operations</li>
 *   <li>Proper driver cleanup</li>
 * </ul>
 * 
 * @author Selenium Intro Course
 * @version 1.0
 * @see org.openqa.selenium.interactions.Actions
 * @see org.openqa.selenium.WebDriver
 */
public class _01_MouseActions {

    /**
     * Main entry point that demonstrates various mouse interaction techniques.
     * 
     * <p>This method performs the following sequence of actions:</p>
     * <ol>
     *   <li>Initializes Chrome WebDriver with implicit wait and maximized window</li>
     *   <li>Navigates to Amazon India homepage</li>
     *   <li>Locates the sign-in link and search input elements</li>
     *   <li>Performs a context click (right-click) on the sign-in element</li>
     *   <li>Performs a series of actions on the search box: click, shift+type "akbar", double-click</li>
     *   <li>Properly closes the browser</li>
     * </ol>
     * 
     * <p><strong>Actions Breakdown:</strong></p>
     * <ul>
     *   <li><code>moveToElement(signIn).contextClick()</code> - Moves mouse to sign-in link and right-clicks</li>
     *   <li><code>moveToElement(search).click().keyDown(Keys.SHIFT).sendKeys("akbar").doubleClick()</code> - 
     *       Moves to search box, clicks, holds Shift, types "AKBAR" (uppercase), then double-clicks</li>
     * </ul>
     * 
     * @param args Command line arguments (not used)
     * 
     * @example <caption>Running the mouse actions test:</caption>
     * java _02_mouse_interactions._01_MouseActions
     */
    public static void main(String[] args) {
        // Initialize ChromeDriver instance
        WebDriver driver = new ChromeDriver();

        // Set implicit wait to 5 seconds for element loading
        driver.manage().timeouts().implicitlyWait(Duration.ofSeconds(5));

        // Maximize the browser window for better visibility
        driver.manage().window().maximize();

        // Navigate to Amazon India homepage
        driver.get("https://www.amazon.in/");

        // Locate the sign-in link element using XPath
        // XPath finds the anchor tag with data-nav-role='signin' inside the account list div
        WebElement signIn = driver.findElement(By.xpath("//div[@id='nav-link-accountList']//a[@data-nav-role='signin']"));

        // Locate the search input box using XPath
        WebElement search = driver.findElement(By.xpath("//input[@id='twotabsearchtextbox']"));

        // Create Actions instance for performing complex user interactions
        Actions actions = new Actions(driver);

        // Perform context click (right-click) on the sign-in element
        // moveToElement() moves the mouse cursor to the element
        // contextClick() performs a right-click action
        // build().perform() builds the action sequence and executes it
        actions.moveToElement(signIn).contextClick().build().perform();

        // Perform a sequence of actions on the search input:
        // 1. moveToElement(search) - Move mouse to search box
        // 2. click() - Click on the search box
        // 3. keyDown(Keys.SHIFT) - Press and hold Shift key
        // 4. sendKeys("akbar") - Type "akbar" (appears as "AKBAR" due to Shift)
        // 5. doubleClick() - Perform a double-click
        // build().perform() - Execute the entire sequence
        actions.moveToElement(search).click().keyDown(Keys.SHIFT).sendKeys("akbar").doubleClick().build().perform();

        // Properly close the browser and clean up resources
        driver.quit();
    }
}
